--
-- Name: mv_collection_summary; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_collection_summary AS
 SELECT organization_id,
    academic_year_id,
    transaction_type,
    payment_method,
    count(*) AS total_transactions,
    sum(amount_paid) AS total_collected,
    count(*) FILTER (WHERE (is_void = true)) AS voided_count
   FROM public.transactions
  WHERE (is_void = false)
  GROUP BY organization_id, academic_year_id, transaction_type, payment_method
  WITH NO DATA;


